// // This module implements a 16-bit wide synchronous parallel-in, parallel-out (PIPO) register that outputs the input data (din) on the falling edge of the clock (clk) when the load signal (ld) is deasserted. If the clear signal (clr) is deasserted, the output is set to all ones.
module top_module(dout, din, ld, clr, clk);input [15:0] din;
  input ld, clr, clk;
  output reg [15:0] dout;

  always @(posedge clk)
    if(clr) dout <= 16'b0;
    else if(ld) dout <= din;endmodule
